input.oldString:
export function add(a, b) {
    if (a < 0 && b < 0) {
        return a + b;
    }
    return Math.abs(a) + Math.abs(b);
}

input.newString:
export function add(a, b) {
    if (a < 0 && b < 0) {
        return -(Math.abs(a) + Math.abs(b));
    }
    return a < 0 ? b - Math.abs(a) : a + b;
}

